import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyTrend {
  day: string;
  systolic: number;
  diastolic: number;
}

interface BloodPressureData {
  latestReading: {
    systolic: number;
    diastolic: number;
    category: string;
  };
  weeklyTrend: WeeklyTrend[];
}

export default function Widget() {
  const bloodPressureData = response.data.data as BloodPressureData;
  const { latestReading, weeklyTrend } = bloodPressureData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ fontWeight: 600, color: '#FF5722' }}>
              Blood Pressure
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#4CAF50' }}>
              {latestReading.systolic}/{latestReading.diastolic} mmHg
            </Typography>
            <Chip label={latestReading.category} sx={{ mt: 1, bgcolor: '#E0F7FA', color: '#00796B' }} />
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: weeklyTrend.map(t => t.systolic),
                  color: '#FF5722',
                  label: 'Systolic',
                  curve: 'linear',
                },
                {
                  type: 'line',
                  data: weeklyTrend.map(t => t.diastolic),
                  color: '#4CAF50',
                  label: 'Diastolic',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: weeklyTrend.map(t => t.day),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'pressure' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="pressure"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
